(function(){"use strict";const OA=window.OrbArena;class CharacterBalanceSystem{constructor(){this.budgets=new Map();this.audit=[];this.calculateAll();}calculate(character){const s=character.stats,tag=name=>character.tags.includes(name)?1:0,power=character.powerId?(OA.PowerRegistry.get(character.powerId)?.powerBudget||0):0,defense=s.armor*2.1+s.knockbackResistance*46+s.mass*31+(1-Math.abs(1-s.elasticity))*8,utility=tag("mobilidade")*25+tag("controle")*29+tag("sustentação")*27+tag("invocação")*30+tag("clone")*26+tag("área")*21+tag("tempo")*25+tag("defesa")*20+tag("negação")*24+tag("projétil")*11,raw=s.health*.58+s.damage*5+s.speed*.2+defense+utility+power*2.4+(6-character.difficulty)*3,weaknessCredit=Math.min(32,character.weaknesses.length*7+character.difficulty*2);return Math.round((raw-weaknessCredit)*(OA.CHARACTER_RARITIES[character.rarity]?.budget||1));}calculateAll(){this.budgets.clear();for(const c of OA.CharacterRegistry.all())this.budgets.set(c.id,this.calculate(c));const values=[...this.budgets.values()],average=values.reduce((s,v)=>s+v,0)/Math.max(1,values.length);this.audit=OA.CharacterRegistry.all().map(c=>({id:c.id,budget:this.get(c.id),delta:Math.round((this.get(c.id)/average-1)*100),review:Math.abs(this.get(c.id)/average-1)>.22}));}get(id){return this.budgets.get(id)||0;}nearest(target,candidates){return[...candidates].sort((a,b)=>Math.abs(this.get(a.id)-target)-Math.abs(this.get(b.id)-target));}}OA.CharacterBalanceSystem=CharacterBalanceSystem;}());
